/* Flexbox */
.nav {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

/* CSS Grid */
.cards {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
  gap: 16px;
}

/* Specificity Examples */
#header {
  color: blue;
}

.menu .item {
  color: red;
}

p {
  color: green;
}

/* #header wins because IDs have higher specificity */

/* Relative */
.card {
  position: relative;
}

/* Absolute */
.badge {
  position: absolute;
  top: 8px;
  right: 8px;
}

/* Fixed */
.chat-button {
  position: fixed;
  bottom: 20px;
  right: 20px;
}

/* Sticky */
.header {
  position: sticky;
  top: 0;
}

.container {
  width: 80%;
  padding: 2rem;
}

h1 {
  font-size: 2rem;
}

.card {
  width: 50vw;
  height: 40vh;
}

button {
  font-size: 1.2em;
}

button:hover {
  background: royalblue;
}

li:nth-child(2) {
  color: red;
}

.badge::after {
  content: '✓';
  color: green;
}

p::first-line {
  font-weight: bold;
}

:root {
  --primary-color: #2563eb;
  --border-radius: 8px;
}

[data-theme="dark"] {
  --primary-color: #60a5fa;
}

.button {
  background: var(--primary-color);
  border-radius: var(--border-radius);
}

/* Descendant */
.card p {
  color: blue;
}

/* Direct Child */
.card > p {
  font-weight: bold;
}

/* Adjacent Sibling */
h2 + p {
  margin-top: 0;
}

/* General Sibling */
h2 ~ p {
  color: gray;
}

.card {
  transition: transform 0.2s ease, opacity 0.2s ease;
}

.card:hover {
  transform: translateY(-4px) scale(1.02);
  opacity: 0.9;
}

/* Block */
.card {}

/* Element */
.card__title {}
.card__image {}

/* Modifier */
.card--featured {}
.card__button--disabled {}

.layout {
  display: grid;
  grid-template-columns: 250px 1fr;
  grid-template-areas:
    "header header"
    "sidebar main"
    "footer footer";
  gap: 16px;
}

.header { grid-area: header; }
.sidebar { grid-area: sidebar; }
.main { grid-area: main; }
.footer { grid-area: footer; }

@media (max-width: 768px) {
  .layout {
    grid-template-columns: 1fr;
    grid-template-areas:
      "header"
      "main"
      "sidebar"
      "footer";
  }
}

h1 {
  font-size: clamp(1.5rem, 4vw, 3rem);
}

.container {
  padding: clamp(1rem, 3vw, 2rem);
}

.wrapper {
  container-type: inline-size;
}

.card {
  display: block;
}

@container (min-width: 400px) {
  .card {
    display: flex;
    gap: 1rem;
  }
}

.container {
  height: 300px;
  overflow: auto;
}

.image {
  overflow: hidden;
}

.code-block {
  overflow-x: auto;
}

.card {
  width: 100%;
  max-width: 400px;
  min-width: 250px;
}

.content {
  flex: 1;
  min-width: 0;
}

.hero {
  min-height: 100vh;
}

.overlay {
  opacity: 0;
  pointer-events: none;
}

.box {
  transform: translateX(100px);
  transition: transform .3s ease;
}

/* Transition */
.button:hover {
  background: blue;
  transition: background .3s;
}

/* Animation */
@keyframes spin {
  to { transform: rotate(360deg); }
}
.loader {
  animation: spin 1s linear infinite;
}

.title {
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.triangle {
  width: 0;
  height: 0;
  border-left: 10px solid transparent;
  border-right: 10px solid transparent;
  border-bottom: 20px solid red;
}

.hidden {
  opacity: 0;
  pointer-events: none;
}

.removed {
  display: none;
}
